"""Exception classes for the Crunchyroll API library."""



class CrunchyrollError(Exception):
    """Base class for all errors raised by this library."""


class LoginError(CrunchyrollError):
    """Authentication failed (invalid credentials or expired token)."""


class NotAuthenticatedError(CrunchyrollError):
    """An action that requires a logged-in session was called without one."""


class CloudflareBlockError(CrunchyrollError):
    """The request was blocked by Cloudflare bot protection."""


class NotFoundError(CrunchyrollError):
    """The requested resource could not be found."""


class TMDBError(CrunchyrollError):
    """Error while communicating with the TMDB API."""


class ConfigError(CrunchyrollError):
    """Missing or invalid configuration (e.g. a missing API key)."""


