# from config.py
# ======================================================================
"""Configuration and pluggable session storage.

Credentials are injected by the host application (constructor arguments or a
``Config`` object). This library never reads a .env file on its own; the
calling program is responsible for collecting secrets however it likes.

Token/session data can be persisted through a pluggable ``SessionStore`` so the
host decides *where* tokens live (memory, file, database, keyring, ...).
"""




@dataclass
class Config:
    """Runtime configuration for the Crunchyroll client.

    All fields are supplied by the host application. ``email``/``password`` are
    optional so the client can also be created for anonymous-only calls or be
    populated later via :meth:`CrunchyrollClient.login`.
    """

    email: Optional[str] = None
    password: Optional[str] = None
    locale: str = "en-US"
    locale_fallback: Optional[str] = None
    tmdb_api_key: Optional[str] = None
    user_agent: Optional[str] = None
    timeout: float = 30.0
    # Robustness: automatic retries on transient errors (0 disables).
    max_retries: int = 3
    backoff_factor: float = 0.5
    # Simple in-memory GET cache TTL in seconds (0 disables caching).
    cache_ttl: float = 0.0
    # Encryption: pass sealed (encrypted) credentials + the key instead of plaintext.
    secret_key: Optional[str] = None
    sealed_credentials: Optional[str] = None


class SessionStore(ABC):
    """Abstract token/session storage.

    Implement this to control where session data is cached. Stored payload is a
    plain JSON-serializable dict (access token, refresh token, account id, CMS
    signatures, expiry, ...).
    """

    @abstractmethod
    def load(self) -> Optional[Dict]:
        """Return the stored session dict, or None if nothing is stored."""

    @abstractmethod
    def save(self, data: Dict) -> None:
        """Persist the session dict."""

    @abstractmethod
    def clear(self) -> None:
        """Remove any stored session."""


class MemorySessionStore(SessionStore):
    """Default in-process store. Nothing is written to disk."""

    def __init__(self) -> None:
        self._data: Optional[Dict] = None
        self._lock = threading.Lock()

    def load(self) -> Optional[Dict]:
        with self._lock:
            return dict(self._data) if self._data is not None else None

    def save(self, data: Dict) -> None:
        with self._lock:
            self._data = dict(data)

    def clear(self) -> None:
        with self._lock:
            self._data = None


class FileSessionStore(SessionStore):
    """Optional store that caches the session as a JSON file.

    Useful for standalone/CLI usage so a login survives across runs. The host
    application chooses the path; it is never created implicitly by the library.
    """

    def __init__(self, path: str) -> None:
        self.path = path

    def load(self) -> Optional[Dict]:
        if not os.path.isfile(self.path):
            return None
        try:
            with open(self.path, "r", encoding="utf-8") as fh:
                return json.load(fh)
        except (OSError, json.JSONDecodeError):
            return None

    def save(self, data: Dict) -> None:
        directory = os.path.dirname(os.path.abspath(self.path))
        os.makedirs(directory, exist_ok=True)
        with open(self.path, "w", encoding="utf-8") as fh:
            json.dump(data, fh, indent=2)

    def clear(self) -> None:
        try:
            os.remove(self.path)
        except OSError:
            pass


# ======================================================================
# from crypto.py
# ======================================================================
"""Optional encryption helpers.

When this library is embedded in another project, you usually do not want to
hand it plaintext credentials. These helpers let the host program pass a sealed
(encrypted) credentials blob plus a secret key; the library decrypts it
in-process. The same key can also encrypt the cached session token at rest.

Encryption uses Fernet (AES-128-CBC + HMAC) from the ``cryptography`` package,
an optional dependency. Install it with:  pip install "crunchyroll-api[crypto]"

Note: because the library runs in the same process as the host, there is no
network hop to protect. The value here is that credentials and the token cache
never exist in plaintext at rest or in the host's long-lived config.
"""





def _fernet(key):
    """Return a Fernet instance, raising a helpful error if cryptography is missing."""
    try:
        from cryptography.fernet import Fernet
    except ImportError as exc:  # pragma: no cover - depends on environment
        raise ConfigError(
            "Encryption requires the 'cryptography' package. "
            'Install it with: pip install "crunchyroll-api[crypto]"'
        ) from exc
    if isinstance(key, str):
        key = key.encode()
    return Fernet(key)


def generate_key() -> str:
    """Generate a fresh random Fernet key (store it somewhere safe)."""
    from cryptography.fernet import Fernet  # local import (optional dep)
    return Fernet.generate_key().decode()


def key_from_password(password: str, salt: Optional[bytes] = None) -> Tuple[str, bytes]:
    """Derive a Fernet key from a human password via PBKDF2.

    Returns ``(key, salt)``; keep the salt to derive the same key again.
    """
    try:
        from cryptography.hazmat.primitives import hashes
        from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
    except ImportError as exc:  # pragma: no cover
        raise ConfigError(
            "Encryption requires the 'cryptography' package. "
            'Install it with: pip install "crunchyroll-api[crypto]"'
        ) from exc
    if salt is None:
        salt = os.urandom(16)
    kdf = PBKDF2HMAC(algorithm=hashes.SHA256(), length=32, salt=salt, iterations=480_000)
    key = base64.urlsafe_b64encode(kdf.derive(password.encode()))
    return key.decode(), salt


def seal_credentials(email: str, password: str, key) -> str:
    """Encrypt credentials into an opaque token the host can pass to the client."""
    payload = json.dumps({"email": email, "password": password}).encode()
    return _fernet(key).encrypt(payload).decode()


def unseal_credentials(token, key) -> Dict[str, str]:
    """Decrypt a sealed credentials token back into {'email', 'password'}."""
    if isinstance(token, str):
        token = token.encode()
    try:
        data = _fernet(key).decrypt(token)
    except ConfigError:
        raise
    except Exception as exc:
        raise ConfigError("Could not decrypt credentials (wrong key or corrupt token).") from exc
    return json.loads(data.decode())


class EncryptedFileSessionStore(SessionStore):
    """A :class:`SessionStore` that encrypts the cached session JSON at rest.

    Drop-in replacement for ``FileSessionStore`` when you want the refresh token
    on disk to be encrypted with your key.
    """

    def __init__(self, path: str, key) -> None:
        self.path = path
        self._key = key

    def load(self) -> Optional[Dict]:
        if not os.path.isfile(self.path):
            return None
        try:
            with open(self.path, "rb") as fh:
                blob = fh.read()
            if not blob:
                return None
            return json.loads(_fernet(self._key).decrypt(blob).decode())
        except ConfigError:
            raise
        except Exception:
            return None

    def save(self, data: Dict) -> None:
        directory = os.path.dirname(os.path.abspath(self.path))
        os.makedirs(directory, exist_ok=True)
        blob = _fernet(self._key).encrypt(json.dumps(data).encode())
        with open(self.path, "wb") as fh:
            fh.write(blob)

    def clear(self) -> None:
        try:
            os.remove(self.path)
        except OSError:
            pass


