"""Data models (DTOs) for Crunchyroll objects.

The Crunchyroll API returns deeply nested, partly inconsistent JSON. These
dataclasses normalize the most important fields and keep the raw JSON under
``raw`` for access to special fields.
"""




def _first_image(images: Any, kind: str) -> Optional[str]:
    """Extract the largest image URL of a given kind (poster_tall/poster_wide/thumbnail)."""
    if not isinstance(images, dict):
        return None
    group = images.get(kind)
    if not group:
        return None
    # group is usually a list of lists: [[{...}, {...}]]
    flat: List[dict] = []
    for entry in group:
        if isinstance(entry, list):
            flat.extend(x for x in entry if isinstance(x, dict))
        elif isinstance(entry, dict):
            flat.append(entry)
    if not flat:
        return None
    # highest resolution wins
    best = max(flat, key=lambda i: i.get("width", 0))
    return best.get("source")


@dataclass
class Image:
    poster_tall: Optional[str] = None
    poster_wide: Optional[str] = None
    thumbnail: Optional[str] = None

    @classmethod
    def from_images(cls, images: Any) -> "Image":
        return cls(
            poster_tall=_first_image(images, "poster_tall"),
            poster_wide=_first_image(images, "poster_wide"),
            thumbnail=_first_image(images, "thumbnail"),
        )


@dataclass
class Series:
    id: str
    title: str
    slug: Optional[str] = None
    description: Optional[str] = None
    episode_count: Optional[int] = None
    season_count: Optional[int] = None
    content_rating: Optional[str] = None
    is_dubbed: bool = False
    is_subbed: bool = False
    audio_locales: List[str] = field(default_factory=list)
    subtitle_locales: List[str] = field(default_factory=list)
    keywords: List[str] = field(default_factory=list)
    images: Image = field(default_factory=Image)
    raw: Dict[str, Any] = field(default_factory=dict)

    @classmethod
    def from_json(cls, data: Dict[str, Any]) -> "Series":
        meta = data.get("series_metadata") or data.get("metadata") or {}
        return cls(
            id=data.get("id", ""),
            title=data.get("title", ""),
            slug=data.get("slug_title") or data.get("slug"),
            description=data.get("description") or data.get("promo_description"),
            episode_count=meta.get("episode_count"),
            season_count=meta.get("season_count"),
            content_rating=(meta.get("maturity_ratings") or [None])[0]
            if meta.get("maturity_ratings") else meta.get("content_rating"),
            is_dubbed=bool(meta.get("is_dubbed")),
            is_subbed=bool(meta.get("is_subbed")),
            audio_locales=meta.get("audio_locales", []) or [],
            subtitle_locales=meta.get("subtitle_locales", []) or [],
            keywords=data.get("keywords", []) or [],
            images=Image.from_images(data.get("images")),
            raw=data,
        )


