@dataclass
class Stream:
    """Playback metadata for an episode/movie.

    Note: the actual video is DRM-protected; this library exposes the manifest
    URL, audio locale and subtitle/caption tracks but does not decrypt video.
    Always call the client's ``invalidate_stream`` when done to free the slot.
    """

    id: str
    url: Optional[str] = None
    audio_locale: Optional[str] = None
    audio_role: Optional[str] = None
    playback_type: Optional[str] = None
    token: Optional[str] = None
    uses_stream_limits: bool = False
    hard_subs: Dict[str, str] = field(default_factory=dict)
    subtitles: List[Subtitle] = field(default_factory=list)
    captions: List[Subtitle] = field(default_factory=list)
    versions: List[StreamVersion] = field(default_factory=list)
    raw: Dict[str, Any] = field(default_factory=dict)

    @staticmethod
    def _subs(value: Any) -> List[Subtitle]:
        out: List[Subtitle] = []
        if isinstance(value, dict):
            for locale, entry in value.items():
                if isinstance(entry, dict):
                    out.append(Subtitle.from_json(locale, entry))
        elif isinstance(value, list):
            for entry in value:
                if isinstance(entry, dict):
                    out.append(Subtitle.from_json(entry.get("language", ""), entry))
        return out

    @classmethod
    def from_json(cls, media_id: str, data: Dict[str, Any]) -> "Stream":
        hard: Dict[str, str] = {}
        raw_hard = data.get("hardSubs") or {}
        if isinstance(raw_hard, dict):
            for locale, entry in raw_hard.items():
                if isinstance(entry, dict) and entry.get("url"):
                    hard[locale] = entry["url"]
        session = data.get("session") or {}
        return cls(
            id=media_id,
            url=data.get("url"),
            audio_locale=data.get("audioLocale"),
            audio_role=data.get("audioRole"),
            playback_type=data.get("playbackType"),
            token=data.get("token"),
            uses_stream_limits=bool(session.get("usesStreamLimits")),
            hard_subs=hard,
            subtitles=cls._subs(data.get("subtitles")),
            captions=cls._subs(data.get("captions")),
            versions=[StreamVersion.from_json(v) for v in data.get("versions", [])
                      if isinstance(v, dict)],
            raw=data,
        )


