"""TMDB bridge.

Crunchyroll's API does not index content by TMDB or IMDB id. To support those
lookups we use TMDB as a translation layer:

    TMDB id / IMDB id  ->  canonical + alternative titles (via TMDB)
                       ->  title search against Crunchyroll
                       ->  best fuzzy match

A free TMDB API key is required (https://www.themoviedb.org/settings/api).
"""





TMDB_BASE = "https://api.themoviedb.org/3"


class TMDBClient:
    """Thin client for the few TMDB endpoints we need."""

    def __init__(
        self,
        api_key: str,
        *,
        language: str = "en-US",
        http_session: Optional[requests.Session] = None,
        timeout: float = 30.0,
    ) -> None:
        if not api_key:
            raise ConfigError("A TMDB API key is required for TMDB/IMDB lookups.")
        self.api_key = api_key
        self.language = language
        self.http = http_session or requests.Session()
        self.timeout = timeout

    def _get(self, path: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        params = dict(params or {})
        params["api_key"] = self.api_key
        resp = self.http.get(f"{TMDB_BASE}{path}", params=params, timeout=self.timeout)
        if resp.status_code == 404:
            raise NotFoundError(f"TMDB resource not found: {path}")
        try:
            payload = resp.json()
        except ValueError:
            raise TMDBError(f"[{resp.status_code}] Invalid TMDB response.")
        if not resp.ok:
            message = payload.get("status_message", resp.text[:200]) if isinstance(payload, dict) else resp.text[:200]
            raise TMDBError(f"[{resp.status_code}] {message}")
        return payload

    def titles_from_tmdb(self, tmdb_id: int, media_type: str = "tv") -> List[str]:
        """Return candidate titles for a TMDB id.

        ``media_type`` is "tv" or "movie". Collects the localized title, the
        original title, the English title and alternative titles.
        """
        if media_type not in ("tv", "movie"):
            raise TMDBError("media_type must be 'tv' or 'movie'.")

        details = self._get(
            f"/{media_type}/{tmdb_id}",
            {"language": self.language, "append_to_response": "alternative_titles"},
        )
        titles: List[str] = []

        if media_type == "tv":
            for key in ("name", "original_name"):
                if details.get(key):
                    titles.append(details[key])
            alt = (details.get("alternative_titles") or {}).get("results", [])
            titles.extend(a["title"] for a in alt if a.get("title"))
        else:
            for key in ("title", "original_title"):
                if details.get(key):
                    titles.append(details[key])
            alt = (details.get("alternative_titles") or {}).get("titles", [])
            titles.extend(a["title"] for a in alt if a.get("title"))

        # Also fetch the English title explicitly (anime is often searched in EN).
        try:
            en = self._get(f"/{media_type}/{tmdb_id}", {"language": "en-US"})
            en_title = en.get("name") or en.get("title")
            if en_title:
                titles.append(en_title)
        except (TMDBError, NotFoundError):
            pass

        return _dedupe(titles)

    def titles_from_imdb(self, imdb_id: str) -> Dict[str, Any]:
        """Resolve an IMDB id (ttXXXXXXX) to TMDB media type, id and titles."""
        data = self._get(f"/find/{imdb_id}", {"external_source": "imdb_id"})
        for media_type, key in (("tv", "tv_results"), ("movie", "movie_results")):
            results = data.get(key) or []
            if results:
                tmdb_id = results[0]["id"]
                titles = self.titles_from_tmdb(tmdb_id, media_type)
                return {"media_type": media_type, "tmdb_id": tmdb_id, "titles": titles}
        raise NotFoundError(f"No TMDB match found for IMDB id '{imdb_id}'.")


def _dedupe(items: List[str]) -> List[str]:
    """Order-preserving, case-insensitive de-duplication."""
    seen = set()
    out: List[str] = []
    for item in items:
        key = item.strip().lower()
        if key and key not in seen:
            seen.add(key)
            out.append(item.strip())
    return out


