# from client.py
# ======================================================================
"""Core Crunchyroll client: authentication, session handling and requests."""





# Small leeway (seconds) so we refresh slightly before the token actually expires.
_EXPIRY_LEEWAY = 30

# Crunchyroll caps ``n`` at 100 on list endpoints; larger limits are paginated.
_MAX_PAGE_N = 100


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def _generate_device_id() -> str:
    """Generate a stable-looking random device id (UUID-ish)."""
    chars = string.ascii_lowercase + string.digits

    def block(n: int) -> str:
        return "".join(random.choices(chars, k=n))

    return f"{block(8)}-{block(4)}-{block(4)}-{block(4)}-{block(12)}"


class CrunchyrollClient:
    """Main entry point for the Crunchyroll API.

    Credentials are injected by the host application, either via a ``Config``
    object or keyword arguments. No environment file is read by the library.

    Example:
        client = CrunchyrollClient(email="a@b.de", password="secret", locale="de-DE")
        client.login()
        results = client.search_series("Frieren")
    """

    def __init__(
        self,
        config: Optional[Config] = None,
        *,
        email: Optional[str] = None,
        password: Optional[str] = None,
        locale: Optional[str] = None,
        locale_fallback: Optional[str] = None,
        tmdb_api_key: Optional[str] = None,
        session_store: Optional[SessionStore] = None,
        http_session: Optional[requests.Session] = None,
        device_id: Optional[str] = None,
        sealed_credentials: Optional[str] = None,
        secret_key: Optional[str] = None,
    ) -> None:
        self.config = config or Config()
        # Keyword arguments override the Config object when provided.
        if email is not None:
            self.config.email = email
        if password is not None:
            self.config.password = password
        if locale is not None:
            self.config.locale = locale
        if locale_fallback is not None:
            self.config.locale_fallback = locale_fallback
        if tmdb_api_key is not None:
            self.config.tmdb_api_key = tmdb_api_key
        if sealed_credentials is not None:
            self.config.sealed_credentials = sealed_credentials
        if secret_key is not None:
            self.config.secret_key = secret_key

        # Decrypt sealed credentials (if provided) into email/password in-process.
        if (self.config.sealed_credentials and self.config.secret_key
                and not (self.config.email and self.config.password)):
            from .crypto import unseal_credentials
            creds = unseal_credentials(self.config.sealed_credentials, self.config.secret_key)
            self.config.email = creds.get("email")
            self.config.password = creds.get("password")

        self.store: SessionStore = session_store or MemorySessionStore()
        self.http = http_session or requests.Session()
        self._cache: Dict[str, Any] = {}
        if http_session is None and self.config.max_retries > 0:
            self._install_retries()
        self.device_id = device_id or _generate_device_id()

        # Active account/session state (populated after login).
        self._account: Dict[str, Any] = {}
        self._active_profile_id: Optional[str] = None

        self.http.headers.update(
            {"User-Agent": self.config.user_agent or USER_AGENT}
        )

    # ------------------------------------------------------------------ #
    # Authentication & session
    # ------------------------------------------------------------------ #
    @property
    def is_authenticated(self) -> bool:
        return bool(self._account.get("access_token"))

    @property
    def account_id(self) -> Optional[str]:
        return self._account.get("account_id")

    def login(self, force: bool = False) -> bool:
        """Authenticate and prepare the session.

        Tries to restore a cached session first (unless ``force`` is set),
        otherwise performs a full credential login.
        """
        if not force:
            cached = self.store.load()
            if cached and self._restore(cached):
                return True

        if not (self.config.email and self.config.password):
            raise LoginError("Email and password are required to log in.")

        self._authenticate(refresh=False)
        return True

    def logout(self) -> None:
        """Drop the local session and clear the store."""
        self._account = {}
        self._active_profile_id = None
        self.store.clear()

    def _restore(self, cached: Dict[str, Any]) -> bool:
        """Restore a cached session; refresh if expired."""
        self._account = dict(cached)
        self._active_profile_id = cached.get("active_profile_id")
        self._set_auth_header()
        expires = cached.get("expires")
        if not expires:
            return False
        try:
            expiry = datetime.fromisoformat(expires)
        except ValueError:
            return False
        if _utcnow() >= expiry - timedelta(seconds=_EXPIRY_LEEWAY):
            # Token expired: try a refresh, fall back to full login.
            if cached.get("refresh_token"):
                try:
                    self._authenticate(refresh=True)
                    return True
                except CrunchyrollError:
                    return False
            return False
        return True

    def _auth_body(self, extra: Dict[str, str]) -> Dict[str, str]:
        """Build the shared token-request body (scope + device identity)."""
        body = dict(extra)
        body["scope"] = "offline_access"
        body["device_id"] = self.device_id
        body["device_type"] = DEVICE_TYPE
        return body

    def _authenticate(self, refresh: bool = False, profile_id: Optional[str] = None) -> None:
        """Request a token and load account data.

        Grant selection mirrors the official clients:
        - password                  -> first login with credentials
        - refresh_token             -> renew an existing session
        - refresh_token_profile_id  -> switch to a specific profile
        """
        headers = {
            "Authorization": BASIC_AUTH,
            "Content-Type": "application/x-www-form-urlencoded",
        }

        have_refresh = bool(self._account.get("refresh_token"))

        if profile_id and have_refresh:
            # Explicit profile switch.
            data = self._auth_body({
                "refresh_token": self._account["refresh_token"],
                "grant_type": "refresh_token_profile_id",
                "profile_id": profile_id,
            })
        elif refresh and have_refresh:
            data = self._auth_body({
                "refresh_token": self._account["refresh_token"],
                "grant_type": "refresh_token",
            })
        else:
            data = self._auth_body({
                "username": self.config.email or "",
                "password": self.config.password or "",
                "grant_type": "password",
            })

        resp = self.http.post(
            TOKEN, headers=headers, data=data, timeout=self.config.timeout
        )
        if resp.status_code == 400:
            if refresh or profile_id:
                # Refresh/profile token invalid -> start over with credentials.
                self._account.pop("refresh_token", None)
                return self._authenticate(refresh=False)
            raise LoginError("Failed to authenticate: invalid credentials.")
        token = self._parse_response(resp)

        account: Dict[str, Any] = {}
        account["access_token"] = token["access_token"]
        account["token_type"] = token.get("token_type", "Bearer")
        account["refresh_token"] = token.get("refresh_token")
        account["account_id"] = token.get("account_id")
        account["profile_id"] = token.get("profile_id")
        expires_in = float(token.get("expires_in", 300))
        account["expires"] = (_utcnow() + timedelta(seconds=expires_in)).isoformat()

        # Authorize follow-up requests.
        self._account = account
        self._set_auth_header()

        # /index/v2 -> CMS signing material (bucket, policy, signature, key_pair_id)
        index = self._request("GET", INDEX, authed=True)
        cms = index.get("cms_web") or index.get("cms") or {}
        account["cms_bucket"] = cms.get("bucket", "")
        account["cms_policy"] = cms.get("policy", "")
        account["cms_signature"] = cms.get("signature", "")
        account["cms_key_pair_id"] = cms.get("key_pair_id", "")

        # /accounts/v1/me -> account id (if not present in token)
        try:
            me = self._request("GET", ME, authed=True)
            account["account_id"] = me.get("account_id", account.get("account_id"))
        except CrunchyrollError:
            pass

        # /accounts/v1/me/profile -> default languages
        try:
            profile = self._request("GET", PROFILE, authed=True)
            account["default_audio_language"] = profile.get(
                "preferred_content_audio_language"
            )
            account["default_subtitle_language"] = profile.get(
                "preferred_content_subtitle_language"
            )
            account["profile_name"] = profile.get("profile_name")
        except CrunchyrollError:
            pass

        if profile_id:
            account["active_profile_id"] = profile_id
            self._active_profile_id = profile_id

        self._account = account
        self.store.save(account)

    def _set_auth_header(self) -> None:
        token_type = self._account.get("token_type", "Bearer")
        access = self._account.get("access_token", "")
        if access:
            self.http.headers["Authorization"] = f"{token_type} {access}"

    def _ensure_authenticated(self) -> None:
        if not self.is_authenticated:
            raise NotAuthenticatedError("This action requires login(). Call login() first.")
        # Refresh proactively if the token is about to expire.
        expires = self._account.get("expires")
        if expires:
            try:
                expiry = datetime.fromisoformat(expires)
                if _utcnow() >= expiry - timedelta(seconds=_EXPIRY_LEEWAY):
                    self._authenticate(refresh=True)
            except ValueError:
                pass

    # ------------------------------------------------------------------ #
    # Profiles
    # ------------------------------------------------------------------ #
    def list_profiles(self) -> List[Profile]:
        """Return all profiles of the account (multiprofile)."""
        self._ensure_authenticated()
        data = self._request("GET", MULTIPROFILE, authed=True)
        items = data.get("profiles") or data.get("data") or []
        return [Profile.from_json(p) for p in items]

    def switch_profile(self, profile_id: str) -> bool:
        """Switch the active profile and re-authenticate for it.

        Watchlist, history and custom lists are profile-specific, so a switch
        requires a fresh token bound to the chosen profile.
        """
        self._ensure_authenticated()
        self._authenticate(profile_id=profile_id)
        return True

    @property
    def active_profile_id(self) -> Optional[str]:
        return self._active_profile_id or self._account.get("profile_id")

    # ------------------------------------------------------------------ #
    # Low-level request helpers
    # ------------------------------------------------------------------ #
    def _bucket(self) -> str:
        bucket = self._account.get("cms_bucket")
        if not bucket:
            raise NotAuthenticatedError("CMS bucket missing; login() required.")
        return bucket

    def _cms_params(self) -> Dict[str, str]:
        return {
            "Policy": self._account.get("cms_policy", ""),
            "Signature": self._account.get("cms_signature", ""),
            "Key-Pair-Id": self._account.get("cms_key_pair_id", ""),
        }

    def _request(
        self,
        method: str,
        url: str,
        *,
        params: Optional[Dict[str, Any]] = None,
        data: Optional[Dict[str, Any]] = None,
        json_data: Optional[Dict[str, Any]] = None,
        authed: bool = True,
        cms: bool = False,
        _retry: bool = False,
    ) -> Dict[str, Any]:
        """Perform an API request and return parsed JSON."""
        params = dict(params or {})
        if cms:
            params.update(self._cms_params())

        cache_key = None
        if method.upper() == "GET" and self.config.cache_ttl > 0:
            import time as _time
            cache_key = url + "?" + repr(sorted(params.items()))
            hit = self._cache.get(cache_key)
            if hit and (_time.time() - hit[0]) < self.config.cache_ttl:
                return hit[1]

        resp = self.http.request(
            method,
            url,
            params=params,
            data=data,
            json=json_data,
            timeout=self.config.timeout,
        )

        if resp.status_code == 401 and authed and not _retry:
            # Token likely expired mid-flight: refresh once and retry.
            self._authenticate(refresh=True)
            return self._request(
                method, url, params=params, data=data, json_data=json_data,
                authed=authed, cms=cms, _retry=True,
            )
        result = self._parse_response(resp)
        if cache_key is not None:
            import time as _time
            self._cache[cache_key] = (_time.time(), result)
        return result

    def _parse_response(self, resp: requests.Response) -> Dict[str, Any]:
        status = resp.status_code
        text = resp.text or ""

        # Cloudflare block detection.
        if status in (403, 429, 503) and "cloudflare" in text.lower():
            raise CloudflareBlockError(
                f"[{status}] Request blocked by Cloudflare. Try a different "
                "user agent, IP, or wait before retrying."
            )

        if not text:
            if 200 <= status < 300:
                return {}
            raise CrunchyrollError(f"[{status}] Empty error response.")

        try:
            payload = resp.json()
        except ValueError:
            if 200 <= status < 300:
                return {"data": text}
            raise CrunchyrollError(f"[{status}] {text[:300]}")

        if isinstance(payload, dict) and payload.get("error") == "invalid_grant":
            raise LoginError(f"[{status}] Invalid login credentials.")
        if 200 <= status < 300:
            return payload
        message = ""
        if isinstance(payload, dict):
            message = payload.get("message") or payload.get("error") or str(payload)
        raise CrunchyrollError(f"[{status}] {message}")

    # ------------------------------------------------------------------ #
    # Content lookups
    # ------------------------------------------------------------------ #
    def get_series(self, series_id: str) -> Series:
        """Fetch full series metadata by Crunchyroll series id."""
        self._ensure_authenticated()
        url = SERIES.format(series_id)
        data = self._request(
            "GET", url, params={"locale": self.config.locale}, cms=True
        )
        items = data.get("data") or []
        if not items:
            raise CrunchyrollError(f"Series '{series_id}' not found.")
        return Series.from_json(items[0])

    def get_seasons(self, series_id: str) -> List[Season]:
        """List all seasons of a series."""
        self._ensure_authenticated()
        url = SEASONS.format(series_id)
        data = self._request(
            "GET", url, params={"locale": self.config.locale}, cms=True
        )
        return [Season.from_json(s) for s in data.get("data", [])]

    def get_episodes(self, season_id: str) -> List[Episode]:
        """List all episodes of a season."""
        self._ensure_authenticated()
        url = EPISODES.format(season_id)
        data = self._request(
            "GET", url, params={"locale": self.config.locale}, cms=True
        )
        return [Episode.from_json(e) for e in data.get("data", [])]

    def get_objects(self, ids: Union[str, List[str]]) -> List[Any]:
        """Resolve one or more content ids to their objects (mixed types)."""
        self._ensure_authenticated()
        if isinstance(ids, str):
            ids = [ids]
        url = OBJECTS.format(",".join(ids))
        data = self._request(
            "GET", url, params={"locale": self.config.locale}, cms=True
        )
        return [parse_item(item) for item in data.get("data", [])]

    # ------------------------------------------------------------------ #
    # Search
    # ------------------------------------------------------------------ #
    def search(
        self, query: str, *, search_type: str = "series", limit: int = 20
    ) -> List[Any]:
        """Generic search.

        ``search_type`` is one of: series, movie_listing, episode, top_results.
        """
        self._ensure_authenticated()
        params = {
            "q": query,
            "n": limit,
            "type": search_type,
            "locale": self.config.locale,
        }
        data = self._request("GET", SEARCH, params=params)
        results: List[Any] = []
        groups = data.get("data", [])
        for group in groups:
            for item in group.get("items", []):
                parsed = parse_item(item)
                if parsed is not None:
                    results.append(parsed)
        return results

    def search_series(self, query: str, *, limit: int = 20) -> List[Series]:
        """Search series by name."""
        return [s for s in self.search(query, search_type="series", limit=limit)
                if isinstance(s, Series)]

    def batch_search(
        self, queries: List[str], *, search_type: str = "series", limit: int = 20
    ) -> Dict[str, List[Any]]:
        """Run several searches at once.

        Returns a mapping of each query to its list of results, preserving the
        input order. Useful for resolving many titles in one call, e.g.
        ``batch_search(["frieren", "one piece"])``.
        """
        out: Dict[str, List[Any]] = {}
        for query in queries:
            q = query.strip()
            if not q:
                continue
            out[q] = self.search(q, search_type=search_type, limit=limit)
        return out

    # ------------------------------------------------------------------ #
    # Catalog / browse
    # ------------------------------------------------------------------ #
    def browse(
        self,
        *,
        content_type: str = "series",
        sort_by: str = "alphabetical",
        n: int = 100,
        start: int = 0,
        categories: Optional[List[str]] = None,
        extra_params: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        """Browse the catalog (one page).

        Returns a dict with ``items`` (parsed models), ``total`` and ``raw``.
        ``content_type`` is e.g. series, movie_listing. ``sort_by`` is one of
        alphabetical, popularity, newly_added.
        """
        self._ensure_authenticated()
        params: Dict[str, Any] = {
            "n": n,
            "start": start,
            "type": content_type,
            "sort_by": sort_by,
            "locale": self.config.locale,
        }
        if categories:
            params["categories"] = ",".join(categories)
        if extra_params:
            params.update(extra_params)
        data = self._request("GET", BROWSE, params=params)
        items = [parse_item(i) for i in data.get("data", [])]
        return {"items": items, "total": data.get("total"), "raw": data}

    def iter_all_series(
        self,
        *,
        sort_by: str = "alphabetical",
        page_size: int = 100,
        categories: Optional[List[str]] = None,
    ) -> Iterator[Series]:
        """Yield every series in the catalog, transparently paginating.

        Note: the full catalog is large (thousands of titles). Iterate lazily
        and stop early if you only need a subset.
        """
        start = 0
        total: Optional[int] = None
        while True:
            page = self.browse(
                content_type="series", sort_by=sort_by,
                n=page_size, start=start, categories=categories,
            )
            items = page["items"]
            if total is None:
                total = page.get("total")
            if not items:
                break
            for item in items:
                if isinstance(item, Series):
                    yield item
            start += len(items)
            if total is not None and start >= total:
                break

    def get_all_series(
        self,
        *,
        limit: Optional[int] = None,
        sort_by: str = "alphabetical",
        page_size: int = 100,
        categories: Optional[List[str]] = None,
    ) -> List[Series]:
        """Return all series in the catalog as a list (optionally capped).

        Pass ``limit`` to stop after N titles; omit it to fetch the full catalog.
        """
        out: List[Series] = []
        for series in self.iter_all_series(
            sort_by=sort_by, page_size=page_size, categories=categories
        ):
            out.append(series)
            if limit is not None and len(out) >= limit:
                break
        return out

    # ------------------------------------------------------------------ #
    # Watchlist / history / custom lists
    # ------------------------------------------------------------------ #
    def get_watchlist(self, limit: int = 100) -> List[WatchlistItem]:
        """Return the watchlist of the active profile.

        Crunchyroll caps ``n`` at 100 for this endpoint (a larger value returns
        HTTP 400), so bigger limits are fetched in pages of 100 via the
        ``start`` offset.
        """
        self._ensure_authenticated()
        url = WATCHLIST.format(self.account_id)
        out: List[WatchlistItem] = []
        start = 0
        while len(out) < limit:
            page_n = min(limit - len(out), _MAX_PAGE_N)
            data = self._request(
                "GET", url,
                params={"n": page_n, "start": start, "locale": self.config.locale},
            )
            items = data.get("data", [])
            if not items:
                break
            out.extend(WatchlistItem.from_json(i) for i in items)
            if len(items) < page_n:
                break
            start += len(items)
        return out

    def add_to_watchlist(self, content_id: str) -> bool:
        """Add a series/movie to the watchlist."""
        self._ensure_authenticated()
        url = WATCHLIST.format(self.account_id)
        self._request(
            "POST", url, params={"locale": self.config.locale},
            json_data={"content_id": content_id},
        )
        return True

    def remove_from_watchlist(self, content_id: str) -> bool:
        """Remove a single item from the watchlist."""
        self._ensure_authenticated()
        url = f"{WATCHLIST.format(self.account_id)}/{content_id}"
        self._request("DELETE", url, params={"locale": self.config.locale})
        return True

    def get_continue_watching(self, limit: int = 100) -> List[Any]:
        """Items to continue watching."""
        self._ensure_authenticated()
        url = CONTINUE_WATCHING.format(self.account_id)
        data = self._request(
            "GET", url,
            params={"n": min(limit, _MAX_PAGE_N), "locale": self.config.locale},
        )
        return [parse_item(i) for i in data.get("data", [])]

    def get_history(self, page: int = 1, page_size: int = 50) -> List[Any]:
        """Watch history of the active profile."""
        self._ensure_authenticated()
        url = HISTORY.format(self.account_id)
        data = self._request(
            "GET", url,
            params={"page": page, "page_size": page_size, "locale": self.config.locale},
        )
        return [parse_item(i) for i in data.get("data", [])]

    def list_custom_lists(self) -> List[Dict[str, Any]]:
        """Return the account's custom lists (Crunchylists) with id and name."""
        self._ensure_authenticated()
        url = CUSTOM_LISTS.format(self.account_id)
        data = self._request("GET", url, params={"locale": self.config.locale})
        return data.get("data", [])

    def get_custom_list(self, list_id: str) -> List[Any]:
        """Return the items of a single custom list."""
        self._ensure_authenticated()
        url = CUSTOM_LIST_ITEMS.format(self.account_id, list_id)
        data = self._request("GET", url, params={"locale": self.config.locale})
        return [parse_item(i) for i in data.get("data", [])]

    # ------------------------------------------------------------------ #
    # Context manager support
    # ------------------------------------------------------------------ #
    def __enter__(self) -> "CrunchyrollClient":
        self.login()
        return self

    def __exit__(self, *exc: Any) -> None:
        self.http.close()

    # ------------------------------------------------------------------ #
    # Upcoming anime: simulcast seasons & release calendar
    # ------------------------------------------------------------------ #
    def list_simulcast_seasons(self) -> List[Dict[str, Any]]:
        """Return all simulcast seasons (e.g. 'Winter 2026') as id + title.

        The newest / upcoming season shows up here once Crunchyroll publishes
        it. Pass an id to :meth:`get_season_anime` to list that lineup.
        """
        self._ensure_authenticated()
        data = self._request(
            "GET", SEASON_LIST, params={"locale": self.config.locale}
        )
        out: List[Dict[str, Any]] = []
        for item in data.get("items", data.get("data", [])):
            loc = item.get("localization") or {}
            out.append({
                "id": item.get("id"),
                "title": loc.get("title") or item.get("title"),
                "description": loc.get("description"),
            })
        return out

    def get_season_anime(
        self,
        season_id: str,
        *,
        media_type: str = "series",
        sort_by: str = "popularity",
        page_size: int = 100,
        limit: Optional[int] = None,
    ) -> List[Any]:
        """List all anime of a given simulcast season (paginated).

        Use this with an upcoming season id to see the future lineup.
        """
        self._ensure_authenticated()
        out: List[Any] = []
        start = 0
        total: Optional[int] = None
        while True:
            page = self.browse(
                content_type=media_type, sort_by=sort_by,
                n=page_size, start=start,
                extra_params={"seasonal_tag": season_id},
            )
            items = page["items"]
            if total is None:
                total = page.get("total")
            if not items:
                break
            out.extend(items)
            if limit is not None and len(out) >= limit:
                return out[:limit]
            start += len(items)
            if total is not None and start >= total:
                break
        return out

    def get_release_calendar(
        self, date: Optional[str] = None, *, premium_only: bool = True
    ) -> List[Dict[str, Any]]:
        """Best-effort weekly simulcast release schedule.

        Scrapes the public simulcast calendar page for the week containing
        ``date`` (ISO 'YYYY-MM-DD', default today) and returns scheduled
        episode releases. Note: Crunchyroll usually lists releases only up to
        the current day, and the page markup may change, so this is best-effort.
        """
        import re
        from datetime import date as _date

        if date is None:
            date = _date.today().isoformat()
        url = f"{SIMULCAST_CALENDAR}?date={date}"
        if premium_only:
            url += "&filter=premium"

        resp = self.http.get(url, timeout=self.config.timeout)
        html = getattr(resp, "text", "") or ""

        items: List[Dict[str, Any]] = []
        # Each release is a schema.org microdata block (itemprop attributes).
        for block in re.split(r"<article[^>]*featured-episode", html)[1:]:

            def grab(prop: str, attr: str) -> Optional[str]:
                m = re.search(
                    r'itemprop="%s"[^>]*\b%s="([^"]+)"' % (prop, attr), block
                )
                return m.group(1) if m else None

            name_m = re.search(r'itemprop="name"[^>]*>\s*([^<]+?)\s*<', block)
            items.append({
                "episode_title": name_m.group(1).strip() if name_m else None,
                "episode_number": grab("episodeNumber", "content"),
                "release_time": grab("datePublished", "content"),
                "episode_url": grab("url", "href"),
                "thumbnail": grab("image", "src"),
                "premium": "premium-flag" in block[:2000],
            })
        return items

    # ------------------------------------------------------------------ #
    # Robustness: retries
    # ------------------------------------------------------------------ #
    def _install_retries(self) -> None:
        """Mount an HTTP adapter that retries transient errors with backoff."""
        try:
            from requests.adapters import HTTPAdapter
            from urllib3.util.retry import Retry
        except Exception:
            return
        retry = Retry(
            total=self.config.max_retries,
            backoff_factor=self.config.backoff_factor,
            status_forcelist=(429, 500, 502, 503, 504),
            allowed_methods=frozenset(["GET", "POST", "DELETE"]),
            raise_on_status=False,
        )
        adapter = HTTPAdapter(max_retries=retry)
        self.http.mount("https://", adapter)
        self.http.mount("http://", adapter)

    def clear_cache(self) -> None:
        """Drop the in-memory GET cache."""
        self._cache.clear()

    # ------------------------------------------------------------------ #
    # Anonymous login (public metadata, no account)
    # ------------------------------------------------------------------ #
    def login_anonymous(self) -> bool:
        """Authenticate without a user account for public metadata access.

        Premium/account features (watchlist, history, streams of premium-only
        content) are not available in anonymous mode.
        """
        headers = {
            "Authorization": ANON_BASIC_AUTH,
            "Content-Type": "application/x-www-form-urlencoded",
            "ETP-Anonymous-ID": self.device_id,
        }
        data = self._auth_body({"grant_type": "client_id"})
        resp = self.http.post(
            TOKEN, headers=headers, data=data, timeout=self.config.timeout
        )
        token = self._parse_response(resp)
        account: Dict[str, Any] = {
            "access_token": token["access_token"],
            "token_type": token.get("token_type", "Bearer"),
            "expires": (_utcnow() + timedelta(
                seconds=float(token.get("expires_in", 300)))).isoformat(),
        }
        self._account = account
        self._set_auth_header()
        index = self._request("GET", INDEX, authed=True)
        cms = index.get("cms_web") or index.get("cms") or {}
        account["cms_bucket"] = cms.get("bucket", "")
        account["cms_policy"] = cms.get("policy", "")
        account["cms_signature"] = cms.get("signature", "")
        account["cms_key_pair_id"] = cms.get("key_pair_id", "")
        self._account = account
        return True

    # ------------------------------------------------------------------ #
    # Episode resolution (S/E numbering) & resolve helper
    # ------------------------------------------------------------------ #
    def find_episode(
        self,
        series_id: str,
        season_number: int,
        episode_number: float,
        *,
        audio_locale: Optional[str] = None,
    ) -> Optional[Episode]:
        """Resolve a specific episode by season & episode number.

        Handy for downloaders that work with S/E numbering (e.g. aniworld).
        If several seasons share a number (different dubs), ``audio_locale``
        picks the matching one.
        """
        seasons = self.get_seasons(series_id)
        matching = [s for s in seasons if s.season_number == season_number]
        if audio_locale:
            preferred = [s for s in matching
                         if s.audio_locale == audio_locale
                         or audio_locale in (s.audio_locales or [])]
            matching = preferred or matching
        for season in matching:
            for ep_ in self.get_episodes(season.id):
                if ep_.episode_number == episode_number:
                    return ep_
        return None

    def resolve_series(self, name: str):
        """Find the best-matching series for a name (uses the catalog search)."""
        results = self.search_series(name, limit=20)
        return results[0] if results else None

    def resolve_episode(
        self, name: str, season_number: int, episode_number: float,
        *, audio_locale: Optional[str] = None,
    ) -> Optional[Episode]:
        """One-shot: series name + S/E -> Episode (with id, ready for streams)."""
        series = self.resolve_series(name)
        if not series:
            return None
        return self.find_episode(
            series.id, season_number, episode_number, audio_locale=audio_locale
        )

    # ------------------------------------------------------------------ #
    # Streams & subtitles  (video itself is DRM-protected)
    # ------------------------------------------------------------------ #
    def get_streams(
        self, media_id: str, *, device: str = "web", platform: str = "chrome"
    ) -> Stream:
        """Fetch playback metadata (manifest URL, audio, subtitle tracks).

        The returned :class:`Stream` carries a session ``token``; when you are
        done, call :meth:`invalidate_stream` to free the playback slot. The
        video stream is DRM-protected and is not decrypted by this library.
        """
        self._ensure_authenticated()
        url = PLAYBACK.format(media_id, device, platform)
        data = self._request("GET", url, params={"locale": self.config.locale})
        return Stream.from_json(media_id, data)

    def get_subtitles(self, media_id: str, **kwargs):
        """Convenience: return only the subtitle tracks of a media id."""
        return self.get_streams(media_id, **kwargs).subtitles

    def download_subtitle(self, subtitle) -> bytes:
        """Download the raw subtitle file (.ass/.vtt) for a Subtitle track."""
        resp = self.http.get(subtitle.url, timeout=self.config.timeout)
        return resp.content

    def invalidate_stream(self, media_id: str, token: str) -> bool:
        """Invalidate an active playback session to free the stream slot."""
        url = PLAYBACK_INVALIDATE.format(media_id, token)
        try:
            self._request("DELETE", url)
        except CrunchyrollError:
            return False
        return True

    # ------------------------------------------------------------------ #
    # Discovery: similar, categories, feeds, recommendations
    # ------------------------------------------------------------------ #
    def get_similar(self, series_id: str, *, limit: int = 20) -> List[Any]:
        """Return series/movies similar to the given series."""
        self._ensure_authenticated()
        url = SIMILAR.format(self.account_id)
        data = self._request(
            "GET", url,
            params={"guid": series_id, "n": limit, "locale": self.config.locale},
        )
        return [parse_item(i) for i in data.get("data", [])]

    def list_categories(self) -> List[Dict[str, Any]]:
        """Return all genres/categories with id and localized title."""
        self._ensure_authenticated()
        data = self._request(
            "GET", CATEGORIES_V2, params={"locale": self.config.locale}
        )
        out: List[Dict[str, Any]] = []
        for item in data.get("data", []):
            loc = item.get("localization") or {}
            out.append({
                "id": item.get("id"),
                "title": loc.get("title") or item.get("slug"),
                "slug": item.get("slug"),
            })
        return out

    def get_home_feed(self, limit: int = 50) -> List[Dict[str, Any]]:
        """Return the raw home-feed items (mixed resource types)."""
        self._ensure_authenticated()
        url = HOME_FEED.format(self.account_id)
        data = self._request(
            "GET", url, params={"n": limit, "locale": self.config.locale}
        )
        return data.get("data", [])

    def get_news_feed(self, limit: int = 20) -> Dict[str, Any]:
        """Return Crunchyroll news (top + latest)."""
        self._ensure_authenticated()
        data = self._request(
            "GET", NEWS_FEED,
            params={"top_news_n": limit, "latest_news_n": limit,
                    "locale": self.config.locale},
        )
        return data

    def get_recommendations(self, limit: int = 20) -> List[Any]:
        """Return recommended series/movies for the account."""
        self._ensure_authenticated()
        url = RECOMMENDATIONS.format(self.account_id)
        data = self._request(
            "GET", url, params={"n": limit, "locale": self.config.locale}
        )
        return [parse_item(i) for i in data.get("data", [])]


# ======================================================================
# from finder.py
# ======================================================================
"""High-level finder that resolves names, TMDB ids and IMDB ids to Crunchyroll series.

This ties together the Crunchyroll client and the TMDB bridge. For id-based
lookups it gathers candidate titles from TMDB, searches Crunchyroll for each,
and returns the best fuzzy match.
"""





@dataclass
class MatchResult:
    """A matched series together with the score and the title that matched."""

    series: Series
    score: float
    matched_title: str
    source_title: str


def _normalize(text: str) -> str:
    """Lowercase and strip punctuation/whitespace for comparison."""
    text = text.lower()
    text = re.sub(r"[^\w\s]", " ", text)
    text = re.sub(r"\s+", " ", text)
    return text.strip()


def _similarity(a: str, b: str) -> float:
    """Return a 0..1 similarity score between two titles."""
    na, nb = _normalize(a), _normalize(b)
    if not na or not nb:
        return 0.0
    if na == nb:
        return 1.0
    # Reward containment (e.g. "Frieren" vs "Frieren: Beyond Journey's End").
    if na in nb or nb in na:
        return 0.9
    return SequenceMatcher(None, na, nb).ratio()


class CrunchyrollFinder:
    """Convenience wrapper around :class:`CrunchyrollClient` for resolving content."""

    def __init__(
        self,
        client: CrunchyrollClient,
        tmdb: Optional[TMDBClient] = None,
        *,
        min_score: float = 0.6,
    ) -> None:
        self.client = client
        self._tmdb = tmdb
        self.min_score = min_score

    @property
    def tmdb(self) -> TMDBClient:
        """Lazily create a TMDB client from the Crunchyroll config if needed."""
        if self._tmdb is None:
            key = self.client.config.tmdb_api_key
            if not key:
                raise ConfigError(
                    "TMDB lookups need a TMDB API key. Pass a TMDBClient to "
                    "CrunchyrollFinder or set tmdb_api_key on the client config."
                )
            self._tmdb = TMDBClient(key, language=self.client.config.locale)
        return self._tmdb

    # ------------------------------------------------------------------ #
    # By name
    # ------------------------------------------------------------------ #
    def find_by_name(self, name: str, *, limit: int = 20) -> Optional[MatchResult]:
        """Return the best-matching series for a free-text name, or None."""
        matches = self.rank_by_name(name, limit=limit)
        return matches[0] if matches else None

    def rank_by_name(self, name: str, *, limit: int = 20) -> List[MatchResult]:
        """Return all candidates for a name, ranked by similarity (best first)."""
        candidates = self.client.search_series(name, limit=limit)
        ranked = [
            MatchResult(
                series=s,
                score=_similarity(name, s.title),
                matched_title=s.title,
                source_title=name,
            )
            for s in candidates
        ]
        ranked.sort(key=lambda m: m.score, reverse=True)
        return ranked

    # ------------------------------------------------------------------ #
    # By external id
    # ------------------------------------------------------------------ #
    def find_by_tmdb(
        self, tmdb_id: int, *, media_type: str = "tv", limit: int = 20
    ) -> Optional[MatchResult]:
        """Resolve a TMDB id to a Crunchyroll series via title matching."""
        titles = self.tmdb.titles_from_tmdb(tmdb_id, media_type)
        return self._best_match_for_titles(titles, limit=limit)

    def find_by_imdb(self, imdb_id: str, *, limit: int = 20) -> Optional[MatchResult]:
        """Resolve an IMDB id (ttXXXXXXX) to a Crunchyroll series."""
        info = self.tmdb.titles_from_imdb(imdb_id)
        return self._best_match_for_titles(info["titles"], limit=limit)

    def _best_match_for_titles(
        self, titles: List[str], *, limit: int
    ) -> Optional[MatchResult]:
        """Search Crunchyroll for each candidate title and keep the best match."""
        if not titles:
            raise NotFoundError("No candidate titles available for matching.")

        best: Optional[MatchResult] = None
        for title in titles:
            for series in self.client.search_series(title, limit=limit):
                score = max(_similarity(t, series.title) for t in titles)
                if best is None or score > best.score:
                    best = MatchResult(
                        series=series,
                        score=score,
                        matched_title=series.title,
                        source_title=title,
                    )
                if best and best.score >= 0.99:
                    return best

        if best and best.score >= self.min_score:
            return best
        return None
